def create_hash_table(size):
    return [None] * size

def hash_insert(table, key):
    idx = key % len(table)
    while table[idx] is not None:
        idx = (idx + 1) % len(table)
    table[idx] = key

def hash_search(table, key):
    idx = key % len(table)
    while table[idx] is not None:
        if table[idx] == key:
            return idx
        idx = (idx + 1) % len(table)
    return -1

